module top_module(
    input [3:0] address,
    input read,
    input clk,
    output reg [7:0] data_out
);parameter ROM_SIZE = 16;

reg [7:0] unused_rom [0:ROM_SIZE-1];

initial begin
    unused_rom[0] = 8'h01;
    unused_rom[1] = 8'h02;
    unused_rom[2] = 8'h03;
    unused_rom[3] = 8'h04;
    unused_rom[4] = 8'h05;
    unused_rom[5] = 8'h06;
    unused_rom[6] = 8'h07;
    unused_rom[7] = 8'h08;
    unused_rom[8] = 8'h09;
    unused_rom[9] = 8'h0A;
    unused_rom[10] = 8'h0B;
    unused_rom[11] = 8'h0C;
    unused_rom[12] = 8'h0D;
    unused_rom[13] = 8'h0E;
    unused_rom[14] = 8'h0F;
    unused_rom[15] = 8'h10;
end

always @(posedge clk) begin
    if (read && address < ROM_SIZE) begin
        data_out <= unused_rom[address];
    end
end

endmodule
